// ── Topic buckets ──────────────────────────────────────────────
// Each bucket defines an arXiv search query and a relevance
// threshold (1-10). Papers scored below the threshold are
// dropped before the digest is compiled.
//
// Edit these to match your own research interests.

const topics = [
  {
    label: 'Medical imaging',
    searchQuery:
      'cat:cs.CV AND (all:"medical imaging" OR all:radiology OR all:MRI OR all:CT OR all:ultrasound)',
    threshold: 7
  },
  {
    label: 'Code generation LLMs',
    searchQuery:
      'cat:cs.CL AND (all:"code generation" OR all:"program synthesis" OR all:LLM OR all:"large language model")',
    threshold: 8
  },
  {
    label: 'Multi-agent systems',
    searchQuery:
      'cat:cs.AI AND (all:"multi-agent" OR all:agentic OR all:"tool use" OR all:orchestration)',
    threshold: 7
  }
];

return topics.map(topic => ({
  json: {
    label: topic.label,
    threshold: topic.threshold,
    url:
      'https://export.arxiv.org/api/query?' +
      'search_query=' + encodeURIComponent(topic.searchQuery) +
      '&start=0&max_results=15' +
      '&sortBy=submittedDate&sortOrder=descending'
  }
}));

// ── Helpers ────────────────────────────────────────────────────
const decodeXml = (value) =>
  String(value || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&#x2F;/g, '/');

const extract = (text, regex) => {
  const m = text.match(regex);
  return m ? decodeXml(m[1].trim()) : '';
};

// ── Fetch each topic feed ─────────────────────────────────────
const allItems = [];

for (const item of items) {
  let xml;
  try {
    xml = await this.helpers.httpRequest({
      method: 'GET',
      url: item.json.url,
      json: false,
      timeout: 30000
    });
  } catch (err) {
    // arXiv may rate-limit or time out — skip this bucket
    // and continue with the others.
    console.warn(`arXiv fetch failed for "${item.json.label}": ${err.message}`);
    continue;
  }

  const entries = xml.match(/<entry>[\s\S]*?<\/entry>/g) || [];

  for (const entryXml of entries) {
    const idUrl      = extract(entryXml, /<id>([\s\S]*?)<\/id>/);
    const title      = extract(entryXml, /<title>([\s\S]*?)<\/title>/).replace(/\s+/g, ' ');
    const abstract   = extract(entryXml, /<summary>([\s\S]*?)<\/summary>/).replace(/\s+/g, ' ');
    const published  = extract(entryXml, /<published>([\s\S]*?)<\/published>/);
    const authorTags = [...entryXml.matchAll(/<author>\s*<name>([\s\S]*?)<\/name>\s*<\/author>/g)];
    const authors    = authorTags.map(m => decodeXml(m[1].trim())).join(', ');
    const arxivId    = idUrl.split('/abs/').pop() || idUrl.split('/').pop() || '';

    // Derive the direct-PDF link from the abstract link.
    const pdfLink = idUrl.replace('/abs/', '/pdf/') + '.pdf';

    allItems.push({
      json: {
        arxivId,
        title,
        authors,
        abstract,
        arxivLink: idUrl,
        pdfLink,
        publishDate: published,
        topicLabel: item.json.label,
        threshold: item.json.threshold
      }
    });
  }

  // Be polite to the arXiv API — 3-second pause between requests.
  if (items.indexOf(item) < items.length - 1) {
    await new Promise(r => setTimeout(r, 3000));
  }
}

if (allItems.length === 0) {
  return [{ json: { _empty: true, reason: 'arXiv returned no entries for any topic.' } }];
}

return allItems;

// ── Deduplication with TTL cleanup ────────────────────────────
// Uses n8n workflow static data to remember arXiv IDs across
// executions.  Entries older than 90 days are pruned so the
// store does not grow without bound.

const PRUNE_DAYS = 90;
const staticData = this.getWorkflowStaticData('global');
staticData.seenArxivIds = staticData.seenArxivIds || {};

// Prune stale entries.
const cutoff = Date.now() - PRUNE_DAYS * 86_400_000;
for (const [id, ts] of Object.entries(staticData.seenArxivIds)) {
  if (new Date(ts).getTime() < cutoff) {
    delete staticData.seenArxivIds[id];
  }
}

// Filter to papers we have not seen yet.
const fresh = [];
for (const item of items) {
  if (!item.json.arxivId || item.json._empty) continue;

  if (!staticData.seenArxivIds[item.json.arxivId]) {
    staticData.seenArxivIds[item.json.arxivId] = new Date().toISOString();
    fresh.push({ json: { ...item.json, isNew: true } });
  }
}

if (fresh.length === 0) {
  return [{ json: { _empty: true, reason: 'All papers were previously seen.' } }];
}

return fresh;

// ── Build the summarization prompt for each paper ────────────
const RESEARCH_PROFILE =
  'Deep learning for medical imaging, code generation LLMs, and multi-agent systems.';

return items.map(item => {
  const p = item.json;
  const prompt = [
    `Research profile: ${RESEARCH_PROFILE}`,
    '',
    'Summarize the following arXiv paper in 2-3 plain-language sentences',
    'and rate its relevance to the research profile on a 1-10 scale.',
    '',
    'Return ONLY valid JSON (no markdown fences, no preamble):',
    '{',
    '  "summary": "<2-3 sentence summary>",',
    '  "relevance_score": <integer 1-10>,',
    '  "tags": ["<tag1>", "<tag2>", "<tag3>"]',
    '}',
    '',
    `Title: ${p.title}`,
    `Authors: ${p.authors}`,
    `Abstract: ${p.abstract}`,
    `Topic bucket: ${p.topicLabel}`
  ].join('\n');

  return { json: { ...p, prompt } };
});

