// ── Parse Claude responses and reunite them with paper metadata ──
//
// The httpRequest node replaces item.json with the API response,
// so paper metadata (title, authors, …) is no longer on the item.
// We recover it from the Build LLM Prompt node output, which
// n8n keeps available via $('Build LLM Prompt').all().

const originals = $('Build LLM Prompt').all();
const parsed    = [];

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const paper    = originals[i]?.json || {};

  // Skip items that failed (continueOnFail passes them through).
  if (response.error || response.errorMessage) continue;

  const rawText =
    response.content?.[0]?.text ||
    response.body?.content?.[0]?.text ||
    '';

  if (!rawText) continue;

  let payload;
  try {
    const cleaned = rawText.replace(/```json|```/g, '').trim();
    payload = JSON.parse(cleaned);
  } catch {
    // Unparseable response — skip this paper.
    continue;
  }

  const score     = Number(payload.relevance_score || 0);
  const threshold = Number(paper.threshold || 7);
  if (score < threshold) continue;

  parsed.push({
    json: {
      title:          paper.title          || '(untitled)',
      authors:        paper.authors        || '',
      publishDate:    paper.publishDate    || '',
      arxivLink:      paper.arxivLink      || '',
      pdfLink:        paper.pdfLink        || '',
      topicLabel:     paper.topicLabel     || '',
      summary:        payload.summary      || '',
      relevanceScore: score,
      tags:           Array.isArray(payload.tags) ? payload.tags : []
    }
  });
}

if (parsed.length === 0) {
  return [{ json: { _empty: true, reason: 'No papers met the relevance threshold.' } }];
}

// Sort highest-relevance first.
parsed.sort((a, b) => b.json.relevanceScore - a.json.relevanceScore);

return parsed;

// ── Compile the final Markdown digest ─────────────────────────
const date = new Date().toISOString().slice(0, 10);

// Handle the "no papers" sentinel.
if (items.length === 1 && items[0].json._empty) {
  return [{
    json: {
      markdown: `# 📚 Research Digest — ${date}\n\n_No new papers met the relevance threshold today._`,
      hasEntries: false
    }
  }];
}

// Group papers by topic for readability.
const byTopic = {};
for (const item of items) {
  const label = item.json.topicLabel || 'Uncategorized';
  if (!byTopic[label]) byTopic[label] = [];
  byTopic[label].push(item.json);
}

let body = '';
for (const [topic, papers] of Object.entries(byTopic)) {
  body += `## ${topic}\n\n`;
  for (const p of papers) {
    body += `### ${p.title}\n`;
    body += `- **Authors:** ${p.authors}\n`;
    body += `- **Published:** ${p.publishDate.slice(0, 10)}\n`;
    body += `- **Relevance:** ${p.relevanceScore}/10\n`;
    body += `- **Tags:** ${p.tags.join(', ')}\n`;
    body += `- **Summary:** ${p.summary}\n`;
    body += `- **arXiv:** [${p.arxivLink}](${p.arxivLink}) · [PDF](${p.pdfLink})\n\n`;
  }
}

const totalPapers = items.length;
const topicCount  = Object.keys(byTopic).length;

const markdown = [
  `# 📚 Research Digest — ${date}`,
  '',
  `> ${totalPapers} paper${totalPapers === 1 ? '' : 's'} across ${topicCount} topic${topicCount === 1 ? '' : 's'}`,
  '',
  body.trimEnd()
].join('\n');

return [{ json: { markdown, hasEntries: true } }];
